<style>
	a {
		/* dimension units are ASCII case-insensitive; tsv (and prettier)
		   canonicalize them to lowercase. (The frequency units hz/khz and the
		   quarter-millimeter q also lowercase but diverge from prettier — covered by
		   units_serialize_case_prettier_divergence.) */
		width: 10px;
		transform: rotate(0.5turn);
		color: hsl(180deg 50% 50%);
	}
</style>
